const input = $input.first().json;
const body = input.body || input;

// Zapier payload shape (configurable). We accept either nested fields or flat top-level keys.
const fb_user_id = (body.fb_user_id || body.user_id || body.member_id || '').toString().trim();
const full_name = (body.name || body.full_name || body.member_name || '').toString().trim();
const first_name = (body.first_name || full_name.split(' ')[0] || '').trim();
const last_name = (body.last_name || full_name.split(' ').slice(1).join(' ') || '').trim();
const email = (body.email || body.member_email || '').toString().toLowerCase().trim();
const joined_at = body.joined_at || body.joinedAt || body.timestamp || new Date().toISOString();
const profile_url = body.profile_url || body.profileUrl || (fb_user_id ? `https://facebook.com/${fb_user_id}` : '');

// Three FB Group entry questions — match either explicit keys or by question position
const hosting_status = (body.hosting_status || body.q1 || body.answer_1 || body.question_1 || '').toString().trim();
const listing_count_raw = (body.listing_count || body.q2 || body.answer_2 || body.question_2 || '').toString().trim();
const headache = (body.headache || body.biggest_headache || body.q3 || body.answer_3 || body.question_3 || '').toString().trim();

// Normalize listing_count to a number when possible
const listing_count_num = parseInt((listing_count_raw.match(/\d+/) || ['0'])[0], 10) || 0;

if (!fb_user_id && !email) {
  throw new Error('Webhook must include at least fb_user_id or email');
}

return [{ json: {
  fb_user_id,
  full_name,
  first_name,
  last_name,
  email,
  profile_url,
  joined_at,
  hosting_status,
  listing_count_raw,
  listing_count_num,
  headache,
  raw_payload: JSON.stringify(body).slice(0, 5000)
}}];

const claude = $input.first().json;
const member = $node['Parse Entry Answers'].json;

const raw = claude?.content?.[0]?.text || '';
if (!raw) throw new Error('Claude returned empty content');

let parsed;
try {
  const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Could not parse Claude JSON: ' + e.message);
}

const valid_personas = ['dreamer','sam','sarah','pam'];
let persona = (parsed.persona || '').toLowerCase().trim();
let confidence = typeof parsed.confidence === 'number' ? parsed.confidence : 0.5;
let reasoning = parsed.reasoning || '';

// Deterministic rule overrides — these win over Claude when answers are clear
const hs = (member.hosting_status || '').toLowerCase();
const headache_lc = (member.headache || '').toLowerCase();
const manages_for_others = /manage|co-?host|property manager|agency|on behalf|clients/.test(hs + ' ' + headache_lc);
const is_planning = /planning|plan to|about to|researching|not yet|haven't started|first listing|future/.test(hs + ' ' + headache_lc);

if (manages_for_others) {
  persona = 'pam';
  confidence = Math.max(confidence, 0.9);
  reasoning = 'Rule override: manages listings for others → pam. ' + reasoning;
} else if (is_planning) {
  persona = 'dreamer';
  confidence = Math.max(confidence, 0.85);
  reasoning = 'Rule override: planning / not yet hosting → dreamer. ' + reasoning;
} else if (member.listing_count_num === 1) {
  persona = 'sam';
  confidence = Math.max(confidence, 0.85);
  reasoning = 'Rule override: 1 listing → sam. ' + reasoning;
} else if (member.listing_count_num >= 3) {
  persona = 'sarah';
  confidence = Math.max(confidence, 0.85);
  reasoning = 'Rule override: 3+ listings → sarah. ' + reasoning;
}

if (!valid_personas.includes(persona)) {
  persona = 'dreamer';
  confidence = 0.3;
}

const headache_tag = parsed.headache_tag || 'general';
const high_confidence = confidence >= 0.75;

return [{ json: {
  ...member,
  persona,
  confidence,
  reasoning,
  headache_tag,
  high_confidence
}}];

const m = $input.first().json;

const greetings = {
  dreamer: `Hey ${m.first_name || 'there'}! Welcome to the group. Saw you're getting ready to launch — that first listing is the biggest leap. If pricing or setup is your sticking point, holler. Free numbers worksheet here if useful: https://thestrledger.com/start`,
  sam: `Hey ${m.first_name || 'there'}! Welcome in. One listing is where most of the leverage gets built — dial in the systems now and the second one is half the work. If ${m.headache_tag || 'the ops side'} is biting you, I have a free template that might help: https://thestrledger.com/start`,
  sarah: `Hey ${m.first_name || 'there'}! Welcome — glad to have a multi-listing host in here. At ${m.listing_count_num || 'your'} listings the spreadsheet sprawl gets real. If you're wrestling with ${m.headache_tag || 'consolidated reporting'}, the Portfolio Bundle was built for exactly that situation: https://thestrledger.com/portfolio`,
  pam: `Hey ${m.first_name || 'there'}! Welcome. Managing for clients is a different beast — owner reporting, fee splits, all of it. If owner statements are your headache, the Pro Manager Bundle handles that: https://thestrledger.com/pro-manager`
};

const message = greetings[m.persona] || greetings.dreamer;
return [{ json: { ...m, dm_message: message } }];

